UPDATE typing_temporary_storage
SET
	result_string = REPEAT('0', #{typingLength})
WHERE 
	user_id = #{loginId} 
	and phrase = #{phrase} 
	and chapter = #{chapter}

mapper.select:
SELECT user_id as userId, phrase, chapter, result_string as resultString, time_string as timeString
FROM typing_temporary_storage
WHERE user_id = #{userId} and phrase = #{phrase} and chapter = #{chapter}

mapper.update:

UPDATE
	typing_temporary_storage

SET
	result_string = #{resultString},
	time_string = #{timeString},
	time_doing = CURRENT_TIMESTAMP

WHERE
	user_id = #{userId}
	and phrase = #{phrase}
	and chapter = #{chapter}

mapper.delete:

DELETE FROM
	typing_temporary_storage

WHERE
	user_id = #{userId}
	and phrase = #{phrase}
	and chapter = #{chapter}

mapper.select:
select chapter
from typing_temporary_storage
where time_doing = (
	select max(time_doing)
	from typing_temporary_storage
	where user_id = #{userId}
	and phrase = #{phrase}
	and result_string is not null
	and INSTR(result_string, '0') > 0
)

select bible_chapters
from bible
where abbreviation_eng = #{phrase}

select c.value from (
select #{chapter} as value
) c left JOIN ( select abbreviation_eng, chapter, count(*) as cnt from typing where login_id = #{loginId} and abbreviation_eng = #{phrase} group by abbreviation_eng, chapter ) d on c.value = d.chapter order by d.cnt asc, c.value asc
